expect(bank.bankTxnId, 'banking init must return a transactionId').to.be.ok;
expect(bank.bankingStatus, 'banking check must produce a terminal status')
    .to.be.oneOf(['Completed', 'Retry', 'Rejected']);
const omni = await fetchOmniStages(this, appId, ['OMNI_1', 'OMNI_PRE', 'OMNI_POST']);
expect(omni.OMNI_1.input, 'OMNI_1 input must be present after offer').to.exist;

